+  } catch {
+    // Fall back to ECDSA P-256
+    console.log('[Identity] Ed25519 not supported, using ECDSA P-256');
+    keyPair = await crypto.subtle.generateKey(
+      { name: 'ECDSA', namedCurve: 'P-256' },
